    public String getPageContent(String url) {
        // Validate input
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        try {
            // Make HTTP GET request and retrieve the response as a String
            String content = restTemplate.getForObject(url, String.class);

            // Handle case where response body is null
            if (content == null) {
                throw new RuntimeException("Failed to fetch content: response body is null");
            }

            return content;

        } catch (HttpClientErrorException e) {
            // Handle 4xx HTTP errors (e.g., 404 Not Found, 403 Forbidden)
            throw new RuntimeException(
                String.format("Client error while fetching URL '%s': %s - %s", 
                    url, e.getStatusCode(), e.getStatusText()), e);

        } catch (HttpServerErrorException e) {
            // Handle 5xx HTTP errors (e.g., 500 Internal Server Error)
            throw new RuntimeException(
                String.format("Server error while fetching URL '%s': %s - %s", 
                    url, e.getStatusCode(), e.getStatusText()), e);

        } catch (ResourceAccessException e) {
            // Handle network/connectivity issues (e.g., timeout, connection refused)
            throw new RuntimeException(
                String.format("Network error while fetching URL '%s': %s", 
                    url, e.getMessage()), e);

        } catch (Exception e) {
            // Handle any other unexpected exceptions
            throw new RuntimeException(
                String.format("Unexpected error while fetching URL '%s': %s", 
                    url, e.getMessage()), e);
        }
    }
}
